import{_ as a,o as r,c as n,ah as o}from"./chunks/framework.CkJUk41Q.js";const P=JSON.parse('{"title":"Kubernetes","description":"","frontmatter":{"title":"Kubernetes","order":2},"headers":[],"relativePath":"server/distribute/cloud/orchestration/index.md","filePath":"server/distribute/cloud/orchestration/index.md"}'),t={name:"server/distribute/cloud/orchestration/index.md"};function s(l,e,i,d,p,c){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="kubernetes" tabindex="-1">Kubernetes <a class="header-anchor" href="#kubernetes" aria-label="Permalink to “Kubernetes”">​</a></h1><p>Kubernetes（K8s）是 Google 开源的容器编排平台，用于自动化部署、扩展和管理容器化应用。Kubernetes 提供服务发现、负载均衡、存储编排、自动扩缩容、自愈等功能，是云原生的事实标准。</p><h2 id="kubernetes-的架构" tabindex="-1">Kubernetes 的架构 <a class="header-anchor" href="#kubernetes-的架构" aria-label="Permalink to “Kubernetes 的架构”">​</a></h2><h3 id="控制平面" tabindex="-1">控制平面 <a class="header-anchor" href="#控制平面" aria-label="Permalink to “控制平面”">​</a></h3><p>控制平面负责集群的决策和响应，管理集群的状态。</p><p>API Server：集群的统一入口，处理 REST 请求，验证和配置数据。</p><p>Etcd：高可用的键值存储，存储集群的配置和状态数据。</p><p>Scheduler：负责调度 Pod 到合适的节点。</p><p>Controller Manager：运行控制器，维护集群的期望状态。</p><p>Cloud Controller Manager：与云服务商 API 交互，管理云资源。</p><h3 id="数据平面" tabindex="-1">数据平面 <a class="header-anchor" href="#数据平面" aria-label="Permalink to “数据平面”">​</a></h3><p>数据平面负责运行容器，由多个节点组成。</p><p>Kubelet：节点代理，负责管理 Pod、与 API Server 通信、汇报节点状态。</p><p>Kube-proxy：网络代理，负责 Service 的负载均衡和网络代理。</p><p>Container Runtime：容器运行时，负责运行容器（containerd、CRI-O）。</p><h2 id="kubernetes-的核心概念" tabindex="-1">Kubernetes 的核心概念 <a class="header-anchor" href="#kubernetes-的核心概念" aria-label="Permalink to “Kubernetes 的核心概念”">​</a></h2><h3 id="pod" tabindex="-1">Pod <a class="header-anchor" href="#pod" aria-label="Permalink to “Pod”">​</a></h3><p>Pod 是 Kubernetes 的最小调度单位，包含一个或多个容器，共享网络和存储。Pod 内的容器可以通过 localhost 通信，共享存储卷。</p><p>Pod 的生命周期：Pending（待调度）、Running（运行中）、Succeeded（成功终止）、Failed（失败终止）、Unknown（状态未知）。</p><p>Pod 的重启策略：Always（总是重启）、OnFailure（失败时重启）、Never（不重启）。</p><h3 id="node" tabindex="-1">Node <a class="header-anchor" href="#node" aria-label="Permalink to “Node”">​</a></h3><p>Node 是集群的工作节点，运行 Pod。Node 的状态：Ready（就绪）、NotReady（未就绪）、OutOfDisk（磁盘不足）、MemoryPressure（内存压力）、DiskPressure（磁盘压力）、PIDPressure（进程数压力）。</p><p>Node 的调度：根据 Pod 的资源请求、节点选择器、亲和性、污点和容忍度，选择合适的节点运行 Pod。</p><h3 id="namespace" tabindex="-1">Namespace <a class="header-anchor" href="#namespace" aria-label="Permalink to “Namespace”">​</a></h3><p>Namespace 是集群的虚拟分区，用于隔离资源。默认命名空间：default（默认）、kube-system（系统组件）、kube-public（公共资源）、kube-node-lease（节点租约）。</p><h3 id="label-和-selector" tabindex="-1">Label 和 Selector <a class="header-anchor" href="#label-和-selector" aria-label="Permalink to “Label 和 Selector”">​</a></h3><p>Label 是键值对，用于标识资源。Selector 根据 Label 选择资源，用于 Pod 选择器、Service 选择器。</p><p>Label 和 Selector 实现资源间的松耦合，Service 通过 Selector 选择 Pod，Deployment 通过 Selector 管理 Pod。</p><h3 id="deployment" tabindex="-1">Deployment <a class="header-anchor" href="#deployment" aria-label="Permalink to “Deployment”">​</a></h3><p>Deployment 管理 Pod 的副本数和版本，支持滚动更新、回滚。Deployment 创建 ReplicaSet，ReplicaSet 管理 Pod。</p><p>Deployment 的更新策略：RollingUpdate（滚动更新）、Recreate（重建）。</p><p>滚动更新：逐个替换 Pod，确保服务不中断。可以配置 maxSurge（最大新增 Pod 数）和 maxUnavailable（最大不可用 Pod 数）。</p><h3 id="service" tabindex="-1">Service <a class="header-anchor" href="#service" aria-label="Permalink to “Service”">​</a></h3><p>Service 是 Pod 的稳定网络入口，提供负载均衡和服务发现。Service 通过 Selector 选择 Pod，将请求负载均衡到后端 Pod。</p><p>Service 的类型：ClusterIP（集群内部访问）、NodePort（通过节点端口访问）、LoadBalancer（通过负载均衡器访问）、ExternalName（外部名称映射）。</p><p>Service 的负载均衡策略：kube-proxy 支持 iptables 和 IPVS 模式，IPVS 性能更好。</p><h3 id="ingress" tabindex="-1">Ingress <a class="header-anchor" href="#ingress" aria-label="Permalink to “Ingress”">​</a></h3><p>Ingress 是 HTTP/HTTPS 路由规则，将外部流量路由到 Service。Ingress 由 Ingress Controller 实现，如 Nginx Ingress Controller、Traefik Ingress Controller。</p><p>Ingress 支持基于主机名、路径的路由，支持 TLS 终止、WebSocket、gRPC。</p><h3 id="configmap-和-secret" tabindex="-1">ConfigMap 和 Secret <a class="header-anchor" href="#configmap-和-secret" aria-label="Permalink to “ConfigMap 和 Secret”">​</a></h3><p>ConfigMap 存储配置数据，以环境变量或挂载文件的方式注入 Pod。</p><p>Secret 存储敏感数据（如密码、Token），Secret 数据以 Base64 编码存储，可以挂载为文件或环境变量。</p><h3 id="persistentvolume-和-persistentvolumeclaim" tabindex="-1">PersistentVolume 和 PersistentVolumeClaim <a class="header-anchor" href="#persistentvolume-和-persistentvolumeclaim" aria-label="Permalink to “PersistentVolume 和 PersistentVolumeClaim”">​</a></h3><p>PersistentVolume（PV）是集群的存储资源，由管理员或 StorageClass 动态创建。</p><p>PersistentVolumeClaim（PVC）是对存储的请求，Pod 通过 PVC 挂载存储。</p><p>StorageClass：存储类，定义存储的类型和参数，支持动态创建 PV。</p><p>PV 的访问模式：ReadWriteOnce（单节点读写）、ReadOnlyMany（多节点只读）、ReadWriteMany（多节点读写）。</p><h2 id="kubernetes-的调度" tabindex="-1">Kubernetes 的调度 <a class="header-anchor" href="#kubernetes-的调度" aria-label="Permalink to “Kubernetes 的调度”">​</a></h2><h3 id="资源请求和限制" tabindex="-1">资源请求和限制 <a class="header-anchor" href="#资源请求和限制" aria-label="Permalink to “资源请求和限制”">​</a></h3><p>resources.requests：Pod 调度所需的最小资源，用于调度决策。</p><p>resources.limits：Pod 可用的最大资源，用于运行时限制。</p><p>CPU 资源：单位为 millicore（1 CPU = 1000m），可压缩，超过限制时被限流。</p><p>内存资源：单位为字节，不可压缩，超过限制时被 OOM Kill。</p><h3 id="节点选择器" tabindex="-1">节点选择器 <a class="header-anchor" href="#节点选择器" aria-label="Permalink to “节点选择器”">​</a></h3><p>nodeSelector：通过 Label 选择节点，简单但功能有限。</p><p>nodeAffinity：节点亲和性，支持 required（必须满足）和 preferred（优先满足）。</p><p>podAffinity 和 podAntiAffinity：Pod 亲和性和反亲和性，控制 Pod 的调度位置。</p><h3 id="污点和容忍度" tabindex="-1">污点和容忍度 <a class="header-anchor" href="#污点和容忍度" aria-label="Permalink to “污点和容忍度”">​</a></h3><p>Taint（污点）：标记节点，拒绝不匹配的 Pod 调度。</p><p>Toleration（容忍度）：Pod 可以容忍污点，即使节点有污点也可以调度。</p><p>常见污点：NoSchedule（不调度）、PreferNoSchedule（尽量不调度）、NoExecute（不调度且驱逐现有 Pod）。</p><h2 id="kubernetes-的自愈" tabindex="-1">Kubernetes 的自愈 <a class="header-anchor" href="#kubernetes-的自愈" aria-label="Permalink to “Kubernetes 的自愈”">​</a></h2><h3 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to “健康检查”">​</a></h3><p>livenessProbe：存活探针，探测容器是否存活，失败时重启容器。</p><p>readinessProbe：就绪探针，探测容器是否就绪，失败时从 Service 移除。</p><p>startupProbe：启动探针，探测容器是否启动，用于慢启动容器。</p><p>探针类型：HTTP GET、TCP Socket、Exec（执行命令）。</p><h3 id="自动重启" tabindex="-1">自动重启 <a class="header-anchor" href="#自动重启" aria-label="Permalink to “自动重启”">​</a></h3><p>Kubernetes 通过 ReplicaSet 确保 Pod 的副本数，Pod 故障时自动重启。</p><h3 id="自动调度" tabindex="-1">自动调度 <a class="header-anchor" href="#自动调度" aria-label="Permalink to “自动调度”">​</a></h3><p>节点故障时，Kubernetes 自动将 Pod 调度到其他节点。</p><h3 id="自动扩缩容" tabindex="-1">自动扩缩容 <a class="header-anchor" href="#自动扩缩容" aria-label="Permalink to “自动扩缩容”">​</a></h3><p>Horizontal Pod Autoscaler（HPA）：根据 CPU、内存或自定义指标自动调整 Pod 副本数。</p><p>Vertical Pod Autoscaler（VPA）：根据资源使用情况自动调整 Pod 的资源请求和限制。</p><p>Cluster Autoscaler：根据 Pod 调度失败情况自动调整节点数量。</p><h2 id="kubernetes-的网络" tabindex="-1">Kubernetes 的网络 <a class="header-anchor" href="#kubernetes-的网络" aria-label="Permalink to “Kubernetes 的网络”">​</a></h2><h3 id="pod-网络" tabindex="-1">Pod 网络 <a class="header-anchor" href="#pod-网络" aria-label="Permalink to “Pod 网络”">​</a></h3><p>Pod 有独立的 IP 地址，Pod 间可以直接通信，跨节点 Pod 通信通过 Overlay 网络（如 VXLAN）。</p><h3 id="service-网络" tabindex="-1">Service 网络 <a class="header-anchor" href="#service-网络" aria-label="Permalink to “Service 网络”">​</a></h3><p>Service 有虚拟 IP（ClusterIP），kube-proxy 通过 iptables 或 IPVS 实现 ClusterIP 的负载均衡。</p><h3 id="ingress-网络" tabindex="-1">Ingress 网络 <a class="header-anchor" href="#ingress-网络" aria-label="Permalink to “Ingress 网络”">​</a></h3><p>Ingress 提供 HTTP/HTTPS 路由，Ingress Controller 实现 Ingress 规则。</p><h2 id="kubernetes-的最佳实践" tabindex="-1">Kubernetes 的最佳实践 <a class="header-anchor" href="#kubernetes-的最佳实践" aria-label="Permalink to “Kubernetes 的最佳实践”">​</a></h2><p>使用标签：为资源添加 Label，便于选择和管理。</p><p>使用命名空间：使用 Namespace 隔离不同环境、不同团队的资源。</p><p>设置资源限制：为 Pod 设置资源请求和限制，避免资源争抢。</p><p>使用健康检查：配置 livenessProbe 和 readinessProbe，确保 Pod 健康。</p><p>使用 ConfigMap 和 Secret：将配置和敏感信息存储在 ConfigMap 和 Secret，不要打包在镜像中。</p><p>使用 HPA：配置 HPA 自动扩缩容，提高资源利用率。</p><p>使用 RBAC：配置 Role-Based Access Control，限制访问权限。</p><p>定期备份 etcd：etcd 存储集群状态，定期备份 etcd 数据。</p><p>Kubernetes 是云原生的事实标准，理解 Kubernetes 的核心概念和最佳实践，有助于构建可扩展、高可用的云原生应用。</p>',92)])])}const b=a(t,[["render",s]]);export{P as __pageData,b as default};
